rs: [],\r\n            all_table_types: [],\r\n            floors: [],\r\n            form: {\r\n                id: null,\r\n                name: null,\r\n                tower_id: null\r\n            }\r\n        };\r\n    },\r\n    methods: {\r\n        initForm() {\r\n            this.form = {\r\n                id: null,\r\n                name: null,\r\n                tower_id: null\r\n            };\r\n        },\r\n        setTitle() {\r\n            this.title =\r\n                this.type == \"floors\"\r\n                    ? \"Pisos\"\r\n                    : this.type == \"towers\"\r\n                    ? \"Torres\"\r\n                    : \"Tipo de habitación\";\r\n        },\r\n        cancel() {\r\n            this.setTitle();\r\n            this.initForm();\r\n        },\r\n        async removeItem(id) {\r\n            try {\r\n                await this.$confirm(\r\n                    \"¿Está seguro de eliminar este registro?\",\r\n                    \"Advertencia\",\r\n                    {\r\n                        confirmButtonText: \"Eliminar\",\r\n                        cancelButtonText: \"Cancelar\",\r\n                        type: \"warning\"\r\n                    }\r\n                );\r\n                try {\r\n                    const response = await this.$http.delete(\r\n                        `/caja/rooms/delete/${this.type}/${id}`\r\n                    );\r\n                    let { message } = response.data;\r\n                    this.$toast.success(message);\r\n                    this.initForm();\r\n                    this.getTables();\r\n                } catch (e) {\r\n                    console.log(e);\r\n                    this.$toast.error(\"Error al eliminar\");\r\n                }\r\n            } catch (e) {}\r\n        },\r\n\r\n        editType(id) {\r\n            this.form = { ...this.all_table_types.find(type => type.id == id) };\r\n\r\n            this.title = \"Editando tipo de habitación\";\r\n